	public ModelAndView getM_PDcurrentDtl(String reportId, String fromdate, String todate, String currency,
			String dtltype, Pageable pageable, String filter, String type, String version,HttpServletRequest req1,Model md) {

		ModelAndView mv = new ModelAndView("BRRS/M_PD");

		String userid = (String) req1.getSession().getAttribute("USERID");
		System.out.println("User Id Maker and Checker: " + userid);
		String role = userProfileRep.getUserRole(userid);
		md.addAttribute("role", role);
		System.out.println("Role: " + role);

		int pageSize = pageable != null ? pageable.getPageSize() : 10;
		int currentPage = pageable != null ? pageable.getPageNumber() : 0;
		int totalRecords = 0;

		try {
// ✅ Parse toDate
			Date parsedDate = null;
			if (todate != null && !todate.isEmpty()) {
				parsedDate = dateformat.parse(todate);
			}

// ✅ Parse filter (reportLable, reportAddlCriteria1)
			String reportLabel = null, reportAddlCriteria1 = null, reportAddlCriteria2 = null, reportAddlCriteria3 = null, reportAddlCriteria4 = null;
			if (filter != null && !filter.isEmpty()) {
				String[] parts = filter.split(",", -1);
				reportLabel = parts.length > 0 ? parts[0] : null;
				reportAddlCriteria1 = parts.length > 1 ? parts[1] : null;
				reportAddlCriteria2 = parts.length > 2 ? parts[2] : null;
				reportAddlCriteria3 = parts.length > 3 ? parts[3] : null;
				reportAddlCriteria4 = parts.length > 4 ? parts[4] : null;
			}

// ✅ ARCHIVAL DATA BRANCH
			if ("ARCHIVAL".equalsIgnoreCase(type) && version != null && !version.isEmpty()) {
				logger.info("Fetching ARCHIVAL data for version {}", version);

				List<M_PD_Archival_Detail_Entity> detailList;

// 🔹 Filtered (ROWID + COLUMNID)
				if (reportLabel != null && !reportLabel.isEmpty()
						&& (isNotEmpty(reportAddlCriteria1) || isNotEmpty(reportAddlCriteria2) || isNotEmpty(reportAddlCriteria3) ||isNotEmpty(reportAddlCriteria4))) {

					logger.info("➡ ARCHIVAL DETAIL QUERY TRIGGERED (with filters)");
					detailList = getArchivalDetailByRowIdAndColumnId(reportLabel, reportAddlCriteria1, reportAddlCriteria2, reportAddlCriteria3,
							reportAddlCriteria4,parsedDate);

				} else {
					logger.info("➡ ARCHIVAL LIST QUERY TRIGGERED (with pagination)");
					detailList = getArchivalDetailByDateAndVersion(parsedDate, version);
					totalRecords = getArchivalDetailCount(parsedDate);
					mv.addObject("pagination", "YES");
				}

				mv.addObject("reportdetails", detailList);
				mv.addObject("reportmaster12", detailList);
				logger.info("ARCHIVAL COUNT: {}", (detailList != null ? detailList.size() : 0));

			} else {
// ✅ CURRENT DATA BRANCH
				logger.info("Fetching CURRENT data for M_PD");

				List<M_PD_Detail_Entity> detailList;

				if (reportLabel != null && !reportLabel.isEmpty()
						&& (isNotEmpty(reportAddlCriteria1) || isNotEmpty(reportAddlCriteria2) || isNotEmpty(reportAddlCriteria3) ||isNotEmpty(reportAddlCriteria4))) {

					logger.info("➡ CURRENT DETAIL QUERY TRIGGERED (with filters)");
					detailList = getDetailByRowIdAndColumnId(reportLabel, reportAddlCriteria1, reportAddlCriteria2, reportAddlCriteria3, reportAddlCriteria4,parsedDate);

				} else {
					logger.info("➡ CURRENT LIST QUERY TRIGGERED (with pagination)");
					detailList = getDetailByDate(parsedDate);
					totalRecords = getDetailCount(parsedDate);
					mv.addObject("pagination", "YES");
				}

				mv.addObject("reportdetails", detailList);
				mv.addObject("reportmaster12", detailList);
				logger.info("CURRENT COUNT: {}", (detailList != null ? detailList.size() : 0));
			}

		} catch (ParseException e) {
			logger.error("Invalid date format: {}", todate, e);
			mv.addObject("errorMessage", "Invalid date format: " + todate);
		} catch (Exception e) {
			logger.error("Unexpected error in getM_PDcurrentDtl", e);
			mv.addObject("errorMessage", "Unexpected error: " + e.getMessage());
		}

// ✅ Common model attributes
		int totalPages = (int) Math.ceil((double) totalRecords / pageSize);
		mv.addObject("displaymode", "Details");
		mv.addObject("currentPage", currentPage);
		mv.addObject("totalPages", totalPages);
		mv.addObject("reportsflag", "reportsflag");
		mv.addObject("menu", reportId);

		logger.info("Total pages calculated: {}", totalPages);
		return mv;
	}
	
	//Helper for null/empty check
		private boolean isNotEmpty(String value) {
			return value != null && !value.trim().isEmpty();
		}


	

		@Transactional
		public void updateReport(M_PD_Manual_Summary_Entity updatedEntity) {

		    System.out.println("Came to services1");
		    System.out.println("Report Date: " + updatedEntity.getReport_date());

		//  Use your query to fetch by date
		    List<M_PD_Manual_Summary_Entity> list = getManualSummaryByDate(updatedEntity.getReport_date());

		    boolean existingRowFound = !list.isEmpty();
		    M_PD_Manual_Summary_Entity existing;
		    if (list.isEmpty()) {
		        // Record not found â€” optionally create it
		        System.out.println("No record found for REPORT_DATE: " + updatedEntity.getReport_date());
		        existing = new M_PD_Manual_Summary_Entity();
		        existing.setReport_date(updatedEntity.getReport_date());
		    } else {
		        existing = list.get(0);
		    }
		    
		 // =========================================
		 // AUDIT OLD COPY
		 // =========================================

		 M_PD_Manual_Summary_Entity oldcopy =
		         new M_PD_Manual_Summary_Entity();

		 BeanUtils.copyProperties(existing, oldcopy);
		    

		    try {

		        // ---------------------------
		        // TABLE 2 ROWS
		        // ---------------------------
		        int[] rows = {8,12,26,35,38,41,46,50,54,61};

		        for (int i : rows) {

		            String prefix = "R" + i + "_";

		            String[] fields = {
		                "30D_90D_PASTDUE","NON_PERFORM_LOANS","NON_ACCRUALS1",
		                "SPECIFIC_PROV1","NO_OF_ACC1","90D_180D_PASTDUE",
		                "NON_ACCRUALS2","SPECIFIC_PROV2","NO_OF_ACC2",
		                "180D_ABOVE_PASTDUE","NON_ACCRUALS3","SPECIFIC_PROV3",
		                "NO_OF_ACC3","TOTAL_NON_ACCRUAL","TOTAL_DUE_LOANS",
		                "TOTAL_PERFORMING_LOAN","VALUE_OF_COLLATERAL",
		                "TOTAL_VALUE_NPL","TOTAL_SPECIFIC_PROV","SPECIFIC_PROV_NPL"
		            };

		            for (String field : fields) {

		                try {

		                    String getterName = "get" + prefix + field;
		                    String setterName = "set" + prefix + field;

		                    Method getter =
		                            M_PD_Manual_Summary_Entity.class.getMethod(getterName);

		                    Method setter =
		                            M_PD_Manual_Summary_Entity.class
		                            .getMethod(setterName, getter.getReturnType());

		                    Object newValue = getter.invoke(updatedEntity);

		                    // Prevent NULL overwrite
		                    if (newValue != null) {
		                        setter.invoke(existing, newValue);
		                    }

		                } catch (NoSuchMethodException e) {
		                    continue;
		                }
		            }
		        }

		        // ---------------------------
		        // ROWS 9 TO 60 (MAIN FIELDS)
		        // ---------------------------
		        for (int i = 9; i <= 60; i++) {

		            if (i == 12 || i == 26 || i == 35 || i == 38
		                    || i == 41 || i == 46 || i == 50 || i == 54)
		                continue;

		            String prefix = "R" + i + "_";

		            String[] fields = {
		                "30D_90D_PASTDUE","NON_PERFORM_LOANS",
		                "NON_ACCRUALS1","SPECIFIC_PROV1","NO_OF_ACC1",
		                "90D_180D_PASTDUE","NON_ACCRUALS2",
		                "SPECIFIC_PROV2","NO_OF_ACC2",
		                "VALUE_OF_COLLATERAL"
		            };

		            for (String field : fields) {

		                try {

		                    String getterName = "get" + prefix + field;
		                    String setterName = "set" + prefix + field;

		                    Method getter =
		                            M_PD_Manual_Summary_Entity.class.getMethod(getterName);

		                    Method setter =
		                            M_PD_Manual_Summary_Entity.class
		                            .getMethod(setterName, getter.getReturnType());

		                    Object newValue = getter.invoke(updatedEntity);

		                    if (newValue != null) {
		                        setter.invoke(existing, newValue);
		                    }

		                } catch (NoSuchMethodException e) {
		                    continue;
		                }
		            }
		        }

		        // ---------------------------
		        // TOTAL COLUMNS
		        // ---------------------------
		        for (int i = 9; i <= 60; i++) {

		            if (i == 12 || i == 26 || i == 35 || i == 38
		                    || i == 41 || i == 46 || i == 50 || i == 54)
		                continue;

		            String prefix = "R" + i + "_";

		            String[] fields = {
		                "TOTAL_NON_ACCRUAL","TOTAL_DUE_LOANS",
		                "TOTAL_PERFORMING_LOAN","TOTAL_VALUE_NPL",
		                "TOTAL_SPECIFIC_PROV","SPECIFIC_PROV_NPL"
		            };

		            for (String field : fields) {

		                try {

		                    String getterName = "get" + prefix + field;
		                    String setterName = "set" + prefix + field;

		                    Method getter =
		                            M_PD_Manual_Summary_Entity.class.getMethod(getterName);

		                    Method setter =
		                            M_PD_Manual_Summary_Entity.class
		                            .getMethod(setterName, getter.getReturnType());

		                    Object newValue = getter.invoke(updatedEntity);

		                    if (newValue != null) {
		                        setter.invoke(existing, newValue);
		                    }

		                } catch (NoSuchMethodException e) {
		                    continue;
		                }
		            }
		        }

		     // =========================================
		     // CHECK CHANGES
		     // =========================================

		     String changes = auditService.getChanges(oldcopy, existing);

		     // =========================================
		     // SAVE TO DATABASE
		     // =========================================

		     saveManualSummary(existing, existingRowFound);

		     // =========================================
		     // AUDIT ONLY IF CHANGES FOUND
		     // =========================================

		     if (changes != null && !changes.trim().isEmpty()) {

		         System.out.println("Audit Length : " + changes.length());

		         if (changes.length() <= 2000) {

		             auditService.compareEntitiesmanual(
		                     oldcopy,
		                     existing,
		                     updatedEntity.getReport_date().toString(),
		                     "M PD Manual Summary Screen",
		                     "BRRS_M_PD_MANUAL_SUMMARY"
		             );

		         } else {

		             System.out.println("Audit skipped because MODI_DETAILS exceeds 2000 characters.");
		         }
		     }

		     System.out.println("Record Updated Successfully");

		    } catch (Exception e) {
		        throw new RuntimeException("Error while updating report fields", e);
		    }
		}

	// Builds and runs an UPDATE (existing row) or INSERT (new row) dynamically from
	// the entity's getters, since M_PD_Manual_Summary_Entity has ~1080 columns.
	private void saveManualSummary(M_PD_Manual_Summary_Entity e, boolean existingRowFound) {
		List<String> columns = new ArrayList<>();
		List<Object> values = new ArrayList<>();
		for (Method getter : M_PD_Manual_Summary_Entity.class.getMethods()) {
			if (!getter.getName().startsWith("get") || getter.getParameterCount() != 0
					|| getter.getName().equals("getClass")) {
				continue;
			}
			String column = getter.getName().substring(3).toUpperCase();
			if (column.equals("REPORT_DATE")) {
				continue;
			}
			try {
				columns.add(column);
				values.add(getter.invoke(e));
			} catch (Exception ex) {
				throw new RuntimeException("Failed reading " + getter.getName(), ex);
			}
		}

		if (existingRowFound) {
			StringBuilder sql = new StringBuilder("UPDATE BRRS_M_PD_MANUAL_SUMMARYTABLE SET ");
			for (int i = 0; i < columns.size(); i++) {
				if (i > 0) sql.append(",");
				sql.append(columns.get(i)).append("=?");
			}
			sql.append(" WHERE REPORT_DATE=?");
			List<Object> params = new ArrayList<>(values);
			params.add(e.getReport_date());
			jdbcTemplate.update(sql.toString(), params.toArray());
		} else {
			StringBuilder sql = new StringBuilder("INSERT INTO BRRS_M_PD_MANUAL_SUMMARYTABLE (REPORT_DATE,");
			sql.append(String.join(",", columns)).append(") VALUES (?");
			for (int i = 0; i < columns.size(); i++) {
				sql.append(",?");
			}
			sql.append(")");
			List<Object> params = new ArrayList<>();
			params.add(e.getReport_date());
			params.addAll(values);
			jdbcTemplate.update(sql.toString(), params.toArray());
		}
	}



