List<M_PD_Manual_RESUB_Summary_Entity> dataList2 = getManualResubSummaryByDateAndVersion(dateformat.parse(todate), version);
if (dataList1.isEmpty() || dataList2.isEmpty()) {
logger.warn("Service: No data found for M_PD report. Returning empty result.");
return new byte[0];
}

